public static int mystery(int[] arr, int low, int high, int num)
{
  int mid = (low + high) / 2;
  if (low > high) return low;
  else if (arr[mid] < num) return mystery(arr, mid + 1, high, num);
  else if (arr[mid] > num) return mystery(arr, low, mid - 1, num);
  else return mid;
}

